const d = $input.first().json;

// Required fields from form's n8nPayload
const required = ['brandName','email','category','revenue','retailer','productDescription'];
const missing = required.filter(k => !d[k] || d[k].toString().trim() === '');

if (missing.length > 0) {
  return [{ json: { valid: false, missing, error: `Missing required fields: ${missing.join(', ')}` } }];
}

const prospectId = `BRAND-${Date.now()}`;
const now = new Date().toISOString();

// Pass through ALL fields from the form payload
return [{ json: {
  valid: true,
  id: prospectId,
  // Core identity
  brandName: (d.brandName || d.company || '').trim(),
  company: (d.company || d.brandName || '').trim(),
  contactName: (d.contactName || `${d.firstName || ''} ${d.lastName || ''}`.trim()),
  firstName: (d.firstName || '').trim(),
  lastName: (d.lastName || '').trim(),
  email: (d.email || '').toLowerCase().trim(),
  phone: (d.phone || '').trim(),
  website: (d.website || '').trim(),
  // Product info
  productName: (d.productName || '').trim(),
  category: d.category,
  productDescription: d.productDescription,
  differentiation: (d.differentiation || ''),
  memberValue: (d.memberValue || ''),
  competitors: (d.competitors || ''),
  // Business info
  revenue: d.revenue,
  retailer: d.retailer,
  preferredModel: (d.preferredModel || 'Roadshow'),
  currentFootprint: (d.currentFootprint || ''),
  timeline: (d.timeline || ''),
  econNotes: (d.econNotes || ''),
  constraints: (d.constraints || ''),
  // Yes/No compliance fields
  has20PctValue: (d.has20PctValue || ''),
  consignmentReady: (d.consignmentReady || ''),
  multiClub: (d.multiClub || ''),
  pricingWorks: (d.pricingWorks || ''),
  canProvideCOGS: (d.canProvideCOGS || ''),
  canBreakEven: (d.canBreakEven || ''),
  hasInsurance: (d.hasInsurance || ''),
  coverage: (d.coverage || ''),
  nutritionalLabel: (d.nutritionalLabel || ''),
  testing: (d.testing || ''),
  certifications: (d.certifications || ''),
  // Meta
  submittedAt: now,
  phase: 1
} }];

const d = $input.first().json;
let score = 0;
const breakdown = {};

// CATEGORY 1: Revenue Scale (25 pts)
const revenueMap = {
  'Under $500K': 5, '$500K – $1M': 12, '$500K - $1M': 12,
  '$1M – $5M': 20, '$1M - $5M': 20,
  '$5M – $20M': 23, '$5M - $20M': 23,
  'Over $20M': 25
};
breakdown.revenue = revenueMap[d.revenue] || 5;
score += breakdown.revenue;

// CATEGORY 2: Retailer Fit (20 pts)
const r = (d.retailer || '').toLowerCase();
breakdown.retailerFit = r.includes('sam') ? 20 : r.includes('costco') ? 18 : r.includes('both') ? 20 : 10;
score += breakdown.retailerFit;

// CATEGORY 3: Product Description Quality (25 pts)
const descLen = (d.productDescription || '').length;
breakdown.productQuality = descLen > 500 ? 25 : descLen > 300 ? 20 : descLen > 150 ? 14 : descLen > 50 ? 8 : 3;
score += breakdown.productQuality;

// CATEGORY 4: Market Readiness - yes/no signals (15 pts)
let readiness = 0;
if (d.has20PctValue === 'yes') readiness += 3;
if (d.consignmentReady === 'yes') readiness += 3;
if (d.multiClub === 'yes') readiness += 3;
if (d.pricingWorks === 'yes') readiness += 3;
if (d.hasInsurance === 'yes') readiness += 3;
breakdown.marketReadiness = Math.min(readiness, 15);
score += breakdown.marketReadiness;

// CATEGORY 5: Economics Clarity (10 pts)
let econ = 0;
if (d.canProvideCOGS === 'yes') econ += 4;
if (d.canBreakEven === 'yes') econ += 3;
if ((d.econNotes || '').length > 20) econ += 3;
breakdown.economics = Math.min(econ, 10);
score += breakdown.economics;

// CATEGORY 6: Category Fit (5 pts)
const highFit = ['Food & Beverage','Health & Beauty','Home & Kitchen','Wellness/Supplements','Pet'];
breakdown.categoryFit = highFit.some(c => (d.category || '').includes(c)) ? 5 : 3;
score += breakdown.categoryFit;

score = Math.round(Math.min(score, 100));

let routing, routingReason;
if (score >= 70) {
  routing = 'AUTO_APPROVE';
  routingReason = 'Score meets auto-approval threshold (>=70). Advancing to Phase 2.';
} else if (score >= 40) {
  routing = 'MANUAL_REVIEW';
  routingReason = 'Score in review range (40-69). Flagged for committee evaluation.';
} else {
  routing = 'AUTO_REJECT';
  routingReason = 'Score below minimum threshold (<40). Auto-rejection with feedback.';
}

return [{ json: { ...d, score, breakdown, routing, routingReason, phase1Complete: true } }];

